function removeDiacritics(s) { return s.replace(/[\u064B-\u065F\u0670]/g, ''); }

function getDifficulty(id) {
  const num = parseInt(id.split('-')[1]);
  if (num <= 120) return 'beginner';
  if (num <= 225) return 'intermediate';
  return 'advanced';
}

